+import { json } from '@sveltejs/kit';
+import type { RequestHandler } from './$types';
+import { db } from '$lib/server/db';
+import { webhook_events } from '$lib/server/db/schema';
+
+type GithubWebhook = {
+	action?: string;
+	repository?: { full_name?: string };
+	sender?: { login?: string };
+	pull_request?: {
+		number?: number;
+		title?: string;
+		head?: { sha?: string };
+	};
+};
+
+export const POST: RequestHandler = async ({ request }) => {
+	const event_type = request.headers.get('x-github-event') ?? 'unknown';
+	const delivery_id = request.headers.get('x-github-delivery') ?? crypto.randomUUID();
+	const body = (await request.json()) as GithubWebhook;
+
+	await db.insert(webhook_events).values({
+		delivery_id,
+		event_type,
+		repository: body.repository?.full_name ?? 'unknown',
+		action: body.action ?? 'unknown',
+		actor: body.sender?.login ?? 'unknown',
+		pull_request_number: body.pull_request?.number ?? null,
+		pull_request_title: body.pull_request?.title ?? null,
+		head_sha: body.pull_request?.head?.sha ?? null,
+		payload: body
+	});
+
+	return json({ ok: true });
+};
+
