+import { jsonb, pgTable, text, timestamp, integer } from 'drizzle-orm/pg-core';
+
+export const webhook_events = pgTable('webhook_events', {
+	delivery_id: text('delivery_id').primaryKey(),
+	event_type: text('event_type').notNull(),
+	repository: text('repository').notNull(),
+	action: text('action').notNull(),
+	actor: text('actor').notNull(),
+	pull_request_number: integer('pull_request_number'),
+	pull_request_title: text('pull_request_title'),
+	head_sha: text('head_sha'),
+	payload: jsonb('payload').notNull(),
+	created_at: timestamp('created_at', { withTimezone: true }).defaultNow().notNull()
+});
