+
+	const expected_buffer = Buffer.from(expected, 'hex');
+	const actual_buffer = Buffer.from(actual, 'hex');
+
+	return (
+		expected_buffer.length === actual_buffer.length &&
+		timingSafeEqual(expected_buffer, actual_buffer)
+	);
