+import { describe, expect, it } from 'vitest';
+import { parse_github_webhook } from './webhooks';
+
+describe('parse_github_webhook', () => {
+	it('normalizes pull request payloads', () => {
+		const event = parse_github_webhook({
+			action: 'opened',
+			repository: { full_name: 'letmediff/app' },
+			sender: { login: 'mona' },
+			pull_request: {
+				number: 42,
+				title: 'Add checkpoint review',
+				head: { sha: 'abc123' }
+			}
+		});
+
+		expect(event).toMatchObject({
+			repository: 'letmediff/app',
+			action: 'opened',
+			actor: 'mona',
+			pull_request_number: 42,
+			pull_request_title: 'Add checkpoint review',
+			head_sha: 'abc123'
+		});
+	});
+
+	it('keeps partial payloads reviewable', () => {
+		const event = parse_github_webhook({ action: 'ping' });
+
+		expect(event).toMatchObject({
+			repository: 'unknown',
+			action: 'ping',
+			actor: 'unknown',
+			pull_request_number: null,
+			pull_request_title: null,
+			head_sha: null
+		});
+	});
+});
