+import { db } from '$lib/server/db';
+import { webhook_events } from '$lib/server/db/schema';
+import { desc } from 'drizzle-orm';
+
+export async function load() {
+	const events = await db
+		.select()
+		.from(webhook_events)
+		.orderBy(desc(webhook_events.created_at))
+		.limit(50);
+
+	return { events };
+}
